{"command": "cd $DOCUMENTS_DIR && python3 << 'EOF'
import subprocess, re

def docx_text(path):
    r = subprocess.run(['pandoc', path, '-t', 'plain'], capture_output=True, text=True)
    return r.stdout

# 1. Letters Testamentary date
print("=== TITLE COMMITMENT: Letters Testamentary ===")
tc = docx_text('title-commitment.docx')
for m in re.finditer(r'.{40}(Letters Testamentary|October 1[14]).{40}', tc):
    print(repr(m.group(0)))

print("\n=== PROBATE CERT: Letters Testamentary / October dates ===")
pc = docx_text('probate-fiduciary-certificate.docx')
for m in re.finditer(r'.{30}(Letters Testamentary|October 1[14]).{50}', pc):
    print(repr(m.group(0)))

print("\n=== MANAGEMENT AGREEMENT effective date ===")
ma = docx_text('management-agreement-termination.docx')
for m in re.finditer(r'.{20}(October 1[05], 2024|Effective Date).{40}', ma):
    print(repr(m.group(0)))

print("\n=== RENT ROLL: Management Agreement effective date ===")
import openpyxl
wb = openpyxl.load_workbook('rent-roll-security-deposits.xlsx', data_only=True)
for ws in wb.worksheets:
    for row in ws.iter_rows(values_only=True):
        for cell in row:
            if cell and isinstance(cell, str) and 'Management Agreement effective' in cell:
                print(repr(cell))
EOF"}

